import { fetchRecipes } from '../services/api';
import { useToast } from '../hooks/useToast';
import { useTranslation } from '../hooks/useTranslation';
import { useRestaurant } from '../hooks/useRestaurant';
import type { Recipe } from '../types';
import { RECIPE_CATEGORIES } from '../types';

// â”€â”€ Types â”€â”€

interface MenuSection {
  category: string;
  recipeIds: number[];
}

interface SavedMenu {
  id: string;
  name: string;
  sections: MenuSection[];
  createdAt: string;
  updatedAt: string;
}

// â”€â”€ Category config â”€â”€

const SECTION_LABELS: Record<string, string> = {
  'Entree': 'Entrees',
  'Entree': 'Entrees',
  'Plat': 'Plats',
  'Dessert': 'Desserts',
  'Boisson': 'Boissons',
  'Accompagnement': 'Accompagnements',
};

const SECTION_ICONS: Record<string, string> = {
  'Entree': 'ðŸ¥—',
  'Plat': 'ðŸ�½ï¸�',
  'Dessert': 'ðŸ�°',
  'Boisson': 'ðŸ¥‚',
  'Accompagnement': 'ðŸ¥–',
};

function getSectionLabel(cat: string): string {
  return SECTION_LABELS[cat] || cat;
}

function getSectionIcon(cat: string): string {
  return SECTION_ICONS[cat] || 'ðŸ“‹';
}

// â”€â”€ Category normalization â”€â”€

const CATEGORY_NORMALIZE: Record<string, string> = {
  'Entree': 'Entree',
  'Entrees': 'Entree',
  'Plats': 'Plat',
  'Desserts': 'Dessert',
  'Suggestions': 'Suggestion',
  'Accompagnements': 'Accompagnement',
  'Boissons': 'Boisson',
};

function normalizeCategory(cat: string): string {
  return CATEGORY_NORMALIZE[cat] || cat;
}

// â”€â”€ Local storage helpers â”€â”€

function loadSavedMenu(): SavedMenu | null {
  try {
    const raw = localStorage.getItem('menuBuilder_currentMenu');
    if (raw) return JSON.parse(raw);
  } catch {}
  return null;
}

function saveSavedMenu(menu: SavedMenu) {
  localStorage.setItem('menuBuilder_currentMenu', JSON.stringify(menu));
}

